module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output A_less_than_B,
    output A_equal_to_B,
    output A_greater_than_B
);

      wire _n01 = A[0] ^ B[0];
  wire _n02 = A[1] ^ B[1];
  wire _n03 = A[2] ^ B[2];
  wire _n04 = A[3] ^ B[3];
  assign A_equal_to_B = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign A_less_than_B = (A < B);
    assign A_greater_than_B = (A > B);

endmodule
